class InMemoryRateLimiter:
    """Simple in-memory fixed-window limiter keyed by client identifier."""

    def __init__(self, window_seconds: float = 60.0) -> None:
        self.window_seconds = window_seconds
        self._events: dict[str, deque[float]] = {}
        self._lock = Lock()

    def allow(self, key: str, limit: int) -> bool:
        """Return True when request is within configured per-minute limit."""
        now = monotonic()
        cutoff = now - self.window_seconds

        with self._lock:
            timeline = [timestamp for timestamp in self._events.get(key, []) if timestamp >= cutoff]
            if len(timeline) >= limit:
                self._events[key] = deque(timeline)
                return False

            timeline.append(now)
            self._events[key] = deque(timeline)
            return True

    def clear(self) -> None:
        """Clear limiter state for deterministic tests."""
        with self._lock:
            self._events.clear()


