@app.middleware("http")
async def request_guards(request: Request, call_next):
    """Enforce host and payload guards and propagate request correlation ids."""
    request_id = request.headers.get("X-Request-ID", str(uuid4()))
    request.state.request_id = request_id

    host_header = request.headers.get("host", "")
    if not is_allowed_host(host_header, settings.allowed_hosts):
        return _guard_error_response(
            request=request,
            request_id=request_id,
            status_code=400,
            code="host_not_allowed",
            message="host_not_allowed",
        )

    if request.headers.get("content-length"):
        try:
            content_length = int(request.headers["content-length"])
        except ValueError:
            return _guard_error_response(
                request=request,
                request_id=request_id,
                status_code=400,
                code="bad_request",
                message="invalid_content_length",
            )

        if content_length > settings.max_payload_bytes:
            return _guard_error_response(
                request=request,
                request_id=request_id,
                status_code=413,
                code="payload_too_large",
                message="payload_too_large",
            )

    if request.method != "OPTIONS" and request.url.path not in AUTH_EXEMPT_PATHS:
        client_key = request.client.host if request.client and request.client.host else "unknown"
        if not rate_limiter.allow(client_key, settings.rate_limit_per_minute):
            return _guard_error_response(
                request=request,
                request_id=request_id,
                status_code=429,
                code="rate_limited",
                message="rate_limited",
                extra_headers={"Retry-After": "60"},
            )

    response = await call_next(request)
    response = apply_security_headers(response, settings.enable_hsts)
    response.headers["X-Request-ID"] = request_id
    return response


